import { useEffect, useMemo, useState } from 'react';
import type { SelectOption } from '@linm-soft/common-components';
import { addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { masterService } from '../../../services/master/masterService';
import type { CustomerDto, CustomerGroupDto } from '../../../services/master/models';
import { buildCustomerGroupSelectOptions } from '../../../utils/customerGroupTree';

export type CustomerFormErrors = Partial<Record<'code' | 'name' | 'customerGroupId', string>>;

export interface UseCustomerFormOptions {
  editing?: CustomerDto | null;
  initialName?: string;
  defaultCustomerType?: string;
  initFormName?: 'create-customer' | 'edit-customer';
  listGroupOptions?: SelectOption[];
  onSaved: (customer: CustomerDto) => void;
  markClean?: () => void;
}

export function useCustomerForm({
  editing = null,
  initialName = '',
  defaultCustomerType = 'Customer',
  initFormName = 'create-customer',
  listGroupOptions = [],
  onSaved,
  markClean,
}: UseCustomerFormOptions) {
  const dispatch = useAppDispatch();
  const { customerGroupOptions: formGroupOptions } = useVoucherInitData(initFormName);
  const [customerGroups, setCustomerGroups] = useState<CustomerGroupDto[]>([]);
  const [form, setForm] = useState<Partial<CustomerDto>>({ isActive: true });
  const [errors, setErrors] = useState<CustomerFormErrors>({});
  const [saving, setSaving] = useState(false);

  const groupById = useMemo(() => {
    const map = new Map<string, CustomerGroupDto>();
    for (const g of customerGroups) map.set(g.customerGroupId, g);
    return map;
  }, [customerGroups]);

  const groupOpts = useMemo(() => {
    const fromInit = formGroupOptions.length > 0 ? formGroupOptions : listGroupOptions;
    if (fromInit.length > 0) return fromInit;
    return buildCustomerGroupSelectOptions(customerGroups);
  }, [formGroupOptions, listGroupOptions, customerGroups]);

  const groupOptsKey = useMemo(
    () => groupOpts.map(o => `${String(o.value)}\t${o.label}`).join('\n'),
    [groupOpts],
  );

  useEffect(() => {
    let cancelled = false;
    const timer = setTimeout(() => {
      masterService.getCustomerGroups({ page: 1, pageSize: 500 })
        .then(data => { if (!cancelled) setCustomerGroups(data.items); })
        .catch(() => { /* non-blocking */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, []);

  useEffect(() => {
    if (editing) {
      setForm({ ...editing });
      setErrors({});
      markClean?.();
      return;
    }
    const firstGroupId = groupOpts[0]?.value != null ? String(groupOpts[0].value) : undefined;
    const group = firstGroupId ? groupById.get(firstGroupId) : undefined;
    setForm({
      isActive: true,
      name: initialName.trim(),
      code: '',
      customerGroupId: firstGroupId,
      customerType: group?.customerType ?? defaultCustomerType,
    });
    setErrors({});
    markClean?.();
  }, [editing, initialName, defaultCustomerType, groupOptsKey, customerGroups, markClean]);

  const clearFieldError = (key: keyof CustomerFormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): CustomerFormErrors => {
    const next: CustomerFormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã đối tượng';
    if (!form.name?.trim()) next.name = 'Nhập tên đối tượng';
    if (!form.customerGroupId?.trim()) next.customerGroupId = 'Chọn nhóm đối tượng';
    return next;
  };

  const applyGroupSelection = (customerGroupId: string) => {
    const g = groupById.get(customerGroupId);
    setForm(f => ({
      ...f,
      customerGroupId,
      customerType: g?.customerType ?? f.customerType ?? defaultCustomerType,
    }));
  };

  const handleSave = async (): Promise<boolean> => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      return false;
    }
    const g = form.customerGroupId ? groupById.get(form.customerGroupId) : undefined;
    const payload: Partial<CustomerDto> = {
      ...form,
      customerType: g?.customerType ?? form.customerType ?? defaultCustomerType,
    };
    setSaving(true);
    try {
      const saved = editing
        ? await masterService.updateCustomer(editing.customerId, payload)
        : await masterService.createCustomer(payload);
      markClean?.();
      dispatch(addToast({
        message: editing ? 'Cập nhật đối tượng thành công' : 'Tạo đối tượng thành công',
        type: 'success',
      }));
      onSaved(saved);
      return true;
    } catch (err: unknown) {
      dispatch(addToast({
        message: err instanceof Error ? err.message : 'Lưu thất bại',
        type: 'error',
      }));
      return false;
    } finally {
      setSaving(false);
    }
  };

  return {
    form,
    setForm,
    errors,
    saving,
    groupOpts,
    clearFieldError,
    applyGroupSelection,
    handleSave,
  };
}
