import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { Button, Select } from '@linm-soft/common-components';
import styles from '../../styles/erpPage.module.css';

/** Allowed page sizes for erp-master catalog grids. */
export const CATALOG_PAGE_SIZES = [50, 100, 200, 500] as const;

export type CatalogPageSize = (typeof CATALOG_PAGE_SIZES)[number];

export const DEFAULT_CATALOG_PAGE_SIZE: CatalogPageSize = 50;

/** @deprecated Use DEFAULT_CATALOG_PAGE_SIZE */
export const CATALOG_PAGE_SIZE = DEFAULT_CATALOG_PAGE_SIZE;

export const CATALOG_PAGE_SIZE_OPTIONS = CATALOG_PAGE_SIZES.map(n => ({
  value: String(n),
  label: String(n),
}));

export interface CatalogListPaginationProps {
  testIdPrefix: string;
  page: number;
  totalCount: number;
  pageSize: number;
  onPageChange: (page: number) => void;
  onPageSizeChange: (pageSize: number) => void;
}

export const CatalogListPagination: React.FC<CatalogListPaginationProps> = ({
  testIdPrefix,
  page,
  totalCount,
  pageSize,
  onPageChange,
  onPageSizeChange,
}) => {
  const totalPages = Math.max(1, Math.ceil(totalCount / pageSize));
  const safePage = Math.min(Math.max(1, page), totalPages);

  return (
    <div className={styles.paginationRow} data-testid={`${testIdPrefix}-pagination`}>
      <span className={styles.totalCount}>
        Tổng: {totalCount} · Trang {safePage}/{totalPages}
      </span>
      <div className={styles.paginationControls}>
        <div
          className={styles.paginationPageSize}
          data-testid={`${testIdPrefix}-field-pageSize`}
        >
          <span className={styles.paginationPageSizeLabel}>Hiển thị</span>
          <Select
            value={String(pageSize)}
            options={CATALOG_PAGE_SIZE_OPTIONS}
            onChange={e => onPageSizeChange(Number(e.target.value))}
            data-testid={`${testIdPrefix}-page-size`}
          />
        </div>
        <div className={styles.headerActions}>
          <Button
            variant="secondary"
            size="sm"
            disabled={safePage <= 1}
            onClick={() => onPageChange(Math.max(1, safePage - 1))}
            data-testid={`${testIdPrefix}-page-prev`}
          >
            Trước
          </Button>
          <Button
            variant="secondary"
            size="sm"
            disabled={safePage >= totalPages}
            onClick={() => onPageChange(Math.min(totalPages, safePage + 1))}
            data-testid={`${testIdPrefix}-page-next`}
          >
            Sau
          </Button>
        </div>
      </div>
    </div>
  );
};

/** Server-side list paging — pair with API `page` + `pageSize`; items come from response. */
export function useCatalogListPaging(initialPageSize: CatalogPageSize = DEFAULT_CATALOG_PAGE_SIZE) {
  const [pageSize, setPageSizeState] = useState<CatalogPageSize>(initialPageSize);
  const [page, setPage] = useState(1);

  const resetPage = useCallback(() => setPage(1), []);

  const setPageSize = useCallback((size: number) => {
    const next = CATALOG_PAGE_SIZES.includes(size as CatalogPageSize)
      ? (size as CatalogPageSize)
      : DEFAULT_CATALOG_PAGE_SIZE;
    setPageSizeState(next);
    setPage(1);
  }, []);

  return { page, setPage, pageSize, setPageSize, resetPage };
}

/** Client-side slice when API returns full list (e.g. tree / company list). */
export function useCatalogPagination<T>(
  items: T[],
  initialPageSize: CatalogPageSize = DEFAULT_CATALOG_PAGE_SIZE,
) {
  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging(initialPageSize);
  const totalCount = items.length;
  const totalPages = Math.max(1, Math.ceil(totalCount / pageSize));
  const pageItems = useMemo(() => {
    const start = (page - 1) * pageSize;
    return items.slice(start, start + pageSize);
  }, [items, page, pageSize]);

  useEffect(() => {
    if (page > totalPages) setPage(totalPages);
  }, [page, totalPages, setPage]);

  return {
    page,
    setPage,
    pageItems,
    totalCount,
    totalPages,
    pageSize,
    setPageSize,
    resetPage,
  };
};

export default CatalogListPagination;
